 454	        const address = runningToplevel.address.startsWith("0x")
 455	          ? runningToplevel.address : "0x" + runningToplevel.address;
 456	        Hyprland.dispatch("focuswindow address:" + address);
 457	      } else if (runningToplevel.wayland !== null)
 458	        runningToplevel.wayland.activate();
