 466	  function resolveTargetMonitor(targetMonitor = "") {
 467	    if (targetMonitor !== "")
 468	      return targetMonitor;
 469	    if (Hyprland.focusedMonitor !== null)
 470	      return Hyprland.focusedMonitor.name;
 471	    return Hyprland.monitors.values.length > 0
 472	      ? Hyprland.monitors.values[0].name : "";
 473	  }
