 475	  function visibleCenterMode() {
 476	    if (appLauncherVisible) return "launcher";
 477	    if (updateSelectorVisible) return "updates";
 478	    if (wifiSelectorVisible) return "wifi";
 479	    if (bluetoothSelectorVisible) return "bluetooth";
 480	    if (mediaOverlayVisible) return "media";
 481	    if (volumeOverlayVisible) return "volume";
 482	    if (brightnessOverlayVisible) return "brightness";
 483	    return "workspaces";
 484	  }
 485	
 486	  function monitorForCenterMode(mode) {
 487	    if (mode === "launcher") return appLauncherTargetMonitor;
 488	    if (mode === "updates") return updateTargetMonitor;
 489	    if (mode === "wifi") return wifiTargetMonitor;
 490	    if (mode === "bluetooth") return bluetoothTargetMonitor;
 491	    if (mode === "media") return mediaTargetMonitor;
 492	    if (mode === "volume") return volumeTargetMonitor;
 493	    if (mode === "brightness") return brightnessTargetMonitor;
 494	    return "";
 495	  }
 496	
 497	  function beginCenterTransition(targetMode, targetMonitor = "") {
 498	    if (centerTransitionPending)
 499	      return false;
 500	    const sourceMode = visibleCenterMode();
 501	    const sourceMonitor = monitorForCenterMode(sourceMode);
 502	    const resolvedTargetMonitor = targetMode === "workspaces"
 503	      ? "" : resolveTargetMonitor(targetMonitor);
 504	    if (sourceMode === targetMode && sourceMonitor === resolvedTargetMonitor)
 505	      return false;
 506	    centerTransitionSourceMode = sourceMode;
 507	    centerTransitionSourceMonitor = sourceMonitor;
 508	    centerTransitionTargetMode = targetMode;
 509	    centerTransitionTargetMonitor = resolvedTargetMonitor;
 510	    centerTransitionPending = true;
 511	    return true;
 512	  }
 513	
 514	  function finishCenterTransition(ownedTransition) {
 515	    if (!ownedTransition)
 516	      return;
 517	    centerTransitionPending = false;
 518	    centerTransitionSerial++;
 519	  }
 520	
 521	  function toggleAppLauncher(targetMonitor = "") {
 522	    const resolvedTarget = resolveTargetMonitor(targetMonitor);
 523	    if (appLauncherVisible && appLauncherTargetMonitor === resolvedTarget)
 524	      hideAppLauncher();
 525	    else
 526	      showAppLauncher(resolvedTarget);
 527	  }
 528	
 529	  function showAppLauncher(targetMonitor = "") {
 530	    const resolvedTarget = resolveTargetMonitor(targetMonitor);
 531	    const preserveQuery = appLauncherVisible;
 532	    const ownsTransition = beginCenterTransition("launcher", resolvedTarget);
 533	    hideMediaOverlay();
 534	    hideWifiSelector();
 535	    hideBluetoothSelector();
 536	    hideUpdateSelector();
 537	    hideVolumeOverlay();
 538	    hideBrightnessOverlay();
 539	    appLauncherTargetMonitor = resolvedTarget;
 540	    if (!preserveQuery)
 541	      appLauncherQuery = "";
 542	    refreshAppLauncherResults();
 543	    appLauncherVisible = true;
 544	    finishCenterTransition(ownsTransition);
 545	  }
 546	
 547	  function hideAppLauncher() {
 548	    if (!appLauncherVisible)
 549	      return;
 550	    const ownsTransition = beginCenterTransition("workspaces");
 551	    appLauncherVisible = false;
 552	    finishCenterTransition(ownsTransition);
 553	  }
 554	
 555	  function showMediaOverlay(targetMonitor = "") {
 556	    if (mprisPlayer === null || appLauncherVisible || wifiSelectorVisible
 557	        || bluetoothSelectorVisible || updateSelectorVisible)
 558	      return;
 559	    const resolvedTarget = resolveTargetMonitor(targetMonitor);
 560	    const ownsTransition = beginCenterTransition("media", resolvedTarget);
 561	    hideVolumeOverlay();
